@dataclass
class Tetromino:
    type: TetrominoType
    rotation: int = 0         # 0-3 index into rotation states
    x: int = 0                # column position of pivot
    y: int = 0                # row position of pivot

    def current_blocks(self) -> List[Tuple[int,int]]:
        shape = TETROMINO_SHAPES[self.type][self.rotation % 4]
        return [(self.x + dx, self.y + dy) for dx, dy in shape]

    def rotate(self, clockwise: bool = True) -> None:
        self.rotation = (self.rotation + (1 if clockwise else -1)) % 4

# Game Grid
class Grid:
    def __init__(self, width: int = 10, height: int = 20):
        self.width: int = width
        self.height: int = height
        self.cells: List[List[Optional[Gem]]] = [
            [None for _ in range(self.width)] for _ in range(self.height)
        ]

    def in_bounds(self, x: int, y: int) -> bool:
        return 0 <= x < self.width and 0 <= y < self.height

    def get_cell(self, x: int, y: int) -> Optional[Gem]:
        if not self.in_bounds(x, y):
            return None
        return self.cells[y][x]

    def set_cell(self, x: int, y: int, gem: Optional[Gem]) -> None:
        if self.in_bounds(x, y):
            self.cells[y][x] = gem

    def clear_cell(self, x: int, y: int) -> None:
        if self.in_bounds(x, y):
            self.cells[y][x] = None

    def reset(self) -> None:
        for y in range(self.height):
            for x in range(self.width):
                self.cells[y][x] = None

    def clear_full_lines(self) -> int:
        lines_cleared = 0
        for y in range(self.height):
            if all(self.cells[y][x] is not None for x in range(self.width)):
                # Clear the line
                for x in range(self.width):
                    self.cells[y][x] = None
                lines_cleared += 1

                # Shift down the lines above
                for y_above in range(y - 1, -1, -1):
                    for x in range(self.width):
                        self.cells[y_above + 1][x] = self.cells[y_above][x]
                # Clear the top line
                for x in range(self.width):
                    self.cells[0][x] = None
        return lines_cleared

    def find_matches(self) -> List[Tuple[int, int]]:
        matches = []
        # Horizontal matches
        for y in range(self.height):
            for x in range(self.width - 2):
                gem1 = self.get_cell(x, y)
                gem2 = self.get_cell(x + 1, y)
                gem3 = self.get_cell(x + 2, y)

                if gem1 and gem2 and gem3 and gem1.color == gem2.color == gem3.color:
                    matches.append((x, y))
                    matches.append((x + 1, y))
                    matches.append((x + 2, y))

        # Vertical matches
        for x in range(self.width):
            for y in range(self.height - 2):
                gem1 = self.get_cell(x, y)
                gem2 = self.get_cell(x, y + 1)
                gem3 = self.get_cell(x, y + 2)
                if gem1 and gem2 and gem3 and gem1.color == gem2.color == gem3.color:
                    matches.append((x, y))
                    matches.append((x, y + 1))
                    matches.append((x, y + 2))

        # Remove duplicate matches
        return list(set(matches))

    def clear_matches(self) -> int:
        matches = self.find_matches()
        cleared_count = 0
        for x, y in matches:
            if self.get_cell(x,y) is not None:
                self.clear_cell(x, y)
                cleared_count+=1
        return cleared_count

    def resolve_chains(self) -> int:
        total_cleared = 0
        cleared = self.clear_matches()
        total_cleared += cleared
        while cleared > 0:
            # Apply gravity: move gems down
            self.apply_gravity()
            cleared = self.clear_matches()
            total_cleared += cleared
        return total_cleared

    def apply_gravity(self):
        for x in range(self.width):
            # Move empty cells to the top
            empty_cells = []
            gems = []
            for y in range(self.height):
                gem = self.get_cell(x, y)
                if gem is None:
                    empty_cells.append(y)
                else:
                    gems.append(gem)

            # Fill the column from the bottom up
            for y in range(self.height):
                if y < len(gems):
                    self.set_cell(x, self.height - 1 - y, gems[len(gems) - 1 - y])
                else:
                    self.set_cell(x, self.height - 1 - y, None)
